cat > ~/.openclaw/workspace-productmanager-agent/skills/workflow-engine/scripts/workflow-engine.js << 'EOF'
/**
 * workflow-engine.js - 可配置流程驱动的多Agent协作引擎
 *
 * 功能：
 * 1. 加载YAML流程配置
 * 2. 状态管理和流转控制
 * 3. Agent间消息分发
 * 4. 广播到飞书/CLI
 * 5. 超时处理
 */

const fs = require('fs');
const path = require('path');
const yaml = require('js-yaml');

class WorkflowEngine {
  constructor(options = {}) {
    this.workflowDir = options.workflowDir || process.cwd();
    this.stateDir = options.stateDir || path.join(process.cwd(), 'states');
    this.debug = options.debug || false;

    // 确保状态目录存在
    if (!fs.existsSync(this.stateDir)) {
      fs.mkdirSync(this.stateDir, { recursive: true });
    }
  }

  /**
   * 加载流程配置
   */
  loadWorkflow(workflowId) {
    let filePath;

    // 先找用户目录，再找内置模板
    const userPath = path.join(this.workflowDir, `${workflowId}.yaml`);
    const templatePath = path.join(__dirname, '../assets/templates', `${workflowId}.yaml`);

    if (fs.existsSync(userPath)) {
      filePath = userPath;
    } else if (fs.existsSync(templatePath)) {
      filePath = templatePath;
    } else {
      throw new Error(`Workflow ${workflowId} not found`);
    }

    const content = fs.readFileSync(filePath, 'utf8');
    const workflow = yaml.load(content);

    this.validateWorkflow(workflow);
    this.log(`Loaded workflow: ${workflow.workflow.name} (${workflowId})`);

    return workflow;
  }

  /**
   * 验证流程配置格式
   */
  validateWorkflow(workflow) {
    if (!workflow.workflow || !workflow.workflow.id || !workflow.workflow.name) {
      throw new Error('Invalid workflow: missing workflow.id or workflow.name');
    }

    if (!workflow.roles || typeof workflow.roles !== 'object') {
      throw new Error('Invalid workflow: missing roles definition');
    }

    if (!Array.isArray(workflow.nodes)) {
      throw new Error('Invalid workflow: nodes must be an array');
    }

    // 验证每个节点
    const nodeIds = new Set();
    workflow.nodes.forEach(node => {
      if (!node.id) {
        throw new Error('Invalid node: missing id');
      }
      if (nodeIds.has(node.id)) {
        throw new Error(`Duplicate node id: ${node.id}`);
      }
      nodeIds.add(node.id);
    });

    // 验证next指向存在的节点
    workflow.nodes.forEach(node => {
      if (node.next && !nodeIds.has(node.next)) {
        throw new Error(`Node ${node.id} references non-existent next node: ${node.next}`);
      }
      if (node.decisions) {
        node.decisions.forEach(decision => {
          if (!nodeIds.has(decision.next)) {
            throw new Error(`Node ${node.id} decision references non-existent next node: ${decision.next}`);
          }
        });
      }
    });

    return true;
  }

  /**
   * 初始化流程状态
   */
  initState(workflow, context = {}) {
    const state = {
      workflowId: workflow.workflow.id,
      workflowName: workflow.workflow.name,
      version: workflow.workflow.version,
      currentNodeId: null,
      status: 'running', // running / completed / paused / failed
      history: [],
      context,
      startedAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      completedAt: null
    };

    // 找到第一个节点
    const firstNode = workflow.nodes[0];
    state.currentNodeId = firstNode.id;

    this.saveState(state);
    this.log(`Initialized workflow state, starting at node: ${firstNode.id}`);

    return state;
  }

  /**
   * 保存流程状态
   */
  saveState(state) {
    state.updatedAt = new Date().toISOString();
    const filePath = path.join(this.stateDir, `${state.workflowId}_${state.startedAt.replace(/[:.]/g, '-')}.json`);
    fs.writeFileSync(filePath, JSON.stringify(state, null, 2), 'utf8');
    return filePath;
  }

  /**
   * 加载流程状态
   */
  loadState(stateFile) {
    const content = fs.readFileSync(stateFile, 'utf8');
    return JSON.parse(content);
  }

  /**
   * 获取当前节点
   */
  getCurrentNode(workflow, state) {
    return workflow.nodes.find(n => n.id === state.currentNodeId);
  }

  /**
   * 获取角色对应的目标session
   */
  getRoleTarget(workflow, roleKey) {
    const role = workflow.roles[roleKey];
    if (!role) {
      throw new Error(`Role ${roleKey} not defined in workflow`);
    }

    const target = {};
    if (role.sessionKey) target.sessionKey = role.sessionKey;
    if (role.label) target.label = role.label;
    if (role.agentId) target.agentId = role.agentId;

    return target;
  }

  /**
   * 构建发送给Agent的任务消息
   */
  buildTaskMessage(workflow, state, node, context) {
    let message = `📋 **流程: [${workflow.workflow.name}]**\n`;
    message += `**当前节点:** ${node.name} (${node.id})\n\n`;

    if (node.description) {
      message += `**描述:** ${node.description}\n\n`;
    }

    if (node.action) {
      message += `**需要你完成:**\n${node.action}\n\n`;
    }

    if (Array.isArray(node.checks) && node.checks.length > 0) {
      message += `**检查项:**\n`;
      node.checks.forEach((check, i) => {
        message += `${i + 1}. ${check}\n`;
      });
      message += '\n';
    }

    if (node.decisions) {
      message += `**请做出决策:**\n`;
      node.decisions.forEach(d => {
        message += `- ${d.key}: ${d.label}\n`;
      });
      message += '\n';
    }

    if (context && Object.keys(context).length > 0) {
      message += `**上下文信息:**\n`;
      for (const [key, value] of Object.entries(context)) {
        message += `- ${key}: ${value}\n`;
      }
    }

    if (node.timeout_hours) {
      message += `\n⏰ 请在 ${node.timeout_hours} 小时内完成`;
    }

    return message;
  }

  /**
   * 广播消息到飞书/CLI
   */
  async broadcast(workflow, message, options = {}) {
    const broadcastConfig = workflow.broadcast || { enabled: true, channel: 'both' };

    if (!broadcastConfig.enabled) {
      return;
    }

    const channel = broadcastConfig.channel;
    const timestamp = new Date().toLocaleString();
    const fullMessage = `[${timestamp}] ${message}`;

    // 输出到CLI
    if (channel === 'cli' || channel === 'both') {
      console.log('\n📢 [Broadcast] ' + fullMessage);
      console.log('');
    }

    // 发送到飞书
    if ((channel === 'feishu' || channel === 'both') && broadcastConfig.feishu_chat_id) {
      try {
        // 调用OpenClaw message工具
        // 这里由外层调用处理
        if (this.broadcastCallback) {
          await this.broadcastCallback(fullMessage, broadcastConfig);
        }
      } catch (err) {
        console.error('Failed to broadcast to Feishu:', err);
      }
    }
  }

  /**
   * 设置广播回调
   */
  setBroadcastCallback(callback) {
    this.broadcastCallback = callback;
  }

  /**
   * 移动到下一个节点
   */
  moveToNextNode(state, node, decisionKey = null) {
    let nextNodeId;

    if (decisionKey && node.decisions) {
      const decision = node.decisions.find(d => d.key === decisionKey);
      if (!decision) {
        throw new Error(`Decision ${decisionKey} not found in node ${node.id}`);
      }
      nextNodeId = decision.next;
    } else if (node.next) {
      nextNodeId = node.next;
    } else if (node.end) {
      nextNodeId = null;
    } else {
      throw new Error(`No next node defined for node ${node.id}`);
    }

    // 记录历史
    state.history.push({
      nodeId: node.id,
      completedAt: new Date().toISOString(),
      decision: decisionKey
    });

    if (!nextNodeId || node.end) {
      // 流程结束
      state.status = 'completed';
      state.completedAt = new Date().toISOString();
      this.log(`Workflow completed: ${state.workflowName}`);
      return null;
    }

    state.currentNodeId = nextNodeId;
    this.saveState(state);
    this.log(`Moved to next node: ${nextNodeId}`);

    return nextNodeId;
  }

  /**
   * 检查是否流程已结束
   */
  isFinished(state) {
    return state.status === 'completed' || state.status === 'failed';
  }

  /**
   * 日志输出
   */
  log(message) {
    if (this.debug) {
      console.log(`[workflow-engine] ${message}`);
    }
  }
}

module.exports = WorkflowEngine;

// 命令行入口
if (require.main === module) {
  const command = process.argv[2];
  const workflowId = process.argv[3];

  const engine = new WorkflowEngine({ debug: true });

  switch (command) {
    case 'list':
      console.log('Available workflows:');
      // 列出所有yaml文件
      const dirs = [
        process.cwd(),
        path.join(__dirname, '../assets/templates')
      ];
      dirs.forEach(dir => {
        if (fs.existsSync(dir)) {
          fs.readdirSync(dir).forEach(file => {
            if (file.endsWith('.yaml') || file.endsWith('.yml')) {
              const id = path.basename(file, '.yaml');
              const content = yaml.load(fs.readFileSync(path.join(dir, file), 'utf8'));
              const name = content.workflow?.name || id;
              console.log(`  - ${id}: ${name}`);
            }
          });
        }
      });
      break;

    case 'validate':
      if (!workflowId) {
        console.error('Usage: node workflow-engine.js validate <workflow-id>');
        process.exit(1);
      }
      try {
        engine.loadWorkflow(workflowId);
        console.log(`✅ Workflow ${workflowId} is valid`);
      } catch (err) {
        console.error(`❌ Validation failed: ${err.message}`);
        process.exit(1);
      }
      break;

    default:
      console.log('Usage:');
      console.log('  node workflow-engine.js list');
      console.log('  node workflow-engine.js validate <workflow-id>');
      break;
  }
}
EOF

