/**
 * init-workflow.js - 创建新的流程配置文件
 *
 * Usage: node init-workflow.js --id <workflow-id> --name "Workflow Name" [--description "desc"] --output <output-dir>
 */

const fs = require('fs');
const path = require('path');
const yaml = require('js-yaml');

// 解析命令行参数
const args = require('minimist')(process.argv.slice(2));

const id = args.id;
const name = args.name;
const description = args.description || '';
const outputDir = args.output || process.cwd();

if (!id || !name) {
  console.error('Usage: node init-workflow.js --id <workflow-id> --name "Workflow Name" [--description "desc"] --output <output-dir>');
  process.exit(1);
}

// 检查id格式
if (!/^[a-z0-9-]+$/.test(id)) {
  console.error('Error: workflow id can only contain lowercase letters, digits, and hyphens');
  process.exit(1);
}

// 模板
const template = `# ${name}
# 自定义工作流程配置

workflow:
  id: "${id}"
  name: "${name}"
  description: "${description}"
  version: "1.0"
  created_at: "${new Date().toISOString().split('T')[0]}"

# 全局广播配置
broadcast:
  enabled: true
  channel: "both"  # feishu | cli | both
  feishu_chat_id: ""  # 配置你的飞书群组id
  show_full_messages: true
  show_progress: true

# 参与角色定义
roles:
  role1:
    name: "角色1名称"
    description: "角色描述"
    session_key: "session-key-here"

  role2:
    name: "角色2名称"
    description: "角色描述"
    session_key: "session-key-here"

# 流程节点定义
nodes:
  - id: "start"
    name: "开始节点"
    role: "role1"
    description: "节点描述"
    action: "需要完成的动作"
    checks:
      - "检查项1"
      - "检查项2"
    next: "next-node"
    broadcast_on_start: true
    broadcast_on_complete: true
    end: false

  - id: "next-node"
    name: "下一个节点"
    role: "role2"
    description: "节点描述"
    action: "需要完成的动作"
    next: "end-node"
    broadcast: true
    end: false

  - id: "end-node"
    name: "流程结束"
    description: "流程完成"
    end: true
`;

// 确保输出目录存在
if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true });
}

const outputPath = path.join(outputDir, `${id}.yaml`);

if (fs.existsSync(outputPath)) {
  console.error(`Error: File already exists: ${outputPath}`);
  console.error('Use a different id or delete the existing file first');
  process.exit(1);
}

fs.writeFileSync(outputPath, template, 'utf8');

console.log(`✅ Created new workflow: ${outputPath}`);
console.log(`   Edit this file to define your workflow nodes and roles`);
console.log(`   Validate with: node ${path.join(__dirname, 'workflow-engine.js')} validate ${id}`);
EOF

cat > ~/.openclaw/workspace-productmanager-agent/skills/workflow-engine/scripts/list-workflows.js << 'EOF'
/**
 * list-workflows.js - 列出所有已定义的工作流程
 */

const fs = require('fs');
const path = require('path');
const yaml = require('js-yaml');

const workflowDirs = [
  process.cwd(),
  path.join(__dirname, '../assets/templates')
];

console.log('📋 Available Workflows:\n');

let count = 0;

workflowDirs.forEach((dir, idx) => {
  if (!fs.existsSync(dir)) {
    return;
  }

  const type = idx === 0 ? 'Custom' : 'Built-in Templates';
  let hasContent = false;

  fs.readdirSync(dir).forEach(file => {
    if (file.endsWith('.yaml') || file.endsWith('.yml')) {
      if (!hasContent) {
        console.log(`**${type}:**\n`);
        hasContent = true;
      }

      const filePath = path.join(dir, file);
      try {
        const content = yaml.load(fs.readFileSync(filePath, 'utf8'));
        const id = content.workflow?.id || path.basify(file, '.yaml');
        const name = content.workflow?.name || id;
        const description = content.workflow?.description || '-';
        const version = content.workflow?.version || '';

        console.log(`  \`${id}\` - **${name}** ${version ? `(v${version})` : ''}`);
        if (description) {
          console.log(`           ${description}`);
        }
        console.log('');
        count++;
      } catch (err) {
        console.log(`  ⚠️  ${file}: Invalid YAML - ${err.message}`);
        console.log('');
      }
    }
  });
});

if (count === 0) {
  console.log('No workflows found.');
  console.log('Create one with: node scripts/init-workflow.js --id my-workflow --name "My Workflow" --output ./');
} else {
  console.log(`Total: ${count} workflow(s)`);
  console.log('\nValidate a workflow: node workflow-engine.js validate <workflow-id>');
  console.log('Delete a workflow: node delete-workflow.js <workflow-id>');
}
EOF

cat > ~/.openclaw/workspace-productmanager-agent/skills/workflow-engine/scripts/delete-workflow.js << 'EOF'
/**
 * delete-workflow.js - 删除自定义工作流程
 *
 * Usage: node delete-workflow.js <workflow-id> [--workflow-dir <dir>]
 */

const fs = require('fs');
const path = require('path');

const workflowId = process.argv[2];
const workflowDir = process.argv[3] || process.cwd();

if (!workflowId) {
  console.error('Usage: node delete-workflow.js <workflow-id> [--workflow-dir <dir>]');
  process.exit(1);
}

const filePath = path.join(workflowDir, `${workflowId}.yaml`);

if (!fs.existsSync(filePath)) {
  console.error(`Error: Workflow file not found: ${filePath}`);
  console.error('Available workflows:');
  if (fs.existsSync(workflowDir)) {
    fs.readdirSync(workflowDir).forEach(file => {
      if (file.endsWith('.yaml')) {
        console.log(`  - ${path.basename(file, '.yaml')}`);
      }
    });
  }
  process.exit(1);
}

// 备份删除
const backupPath = `${filePath}.bak.${Date.now()}`;
fs.renameSync(filePath, backupPath);

console.log(`✅ Deleted workflow: ${workflowId}`);
console.log(`   Backup saved to: ${backupPath}`);
EOF

