}

.btn-danger {
    background: var(--color-danger);
    color: white;
}

.btn-danger:hover {
    filter: brightness(0.9);
}

.btn-sm {
    padding: 4px 10px;
    font-size: 13px;
}

.btn-icon {
    padding: 6px;
    background: transparent;
    color: var(--color-text-secondary);
}

.btn-icon:hover {
    background: var(--color-surface-light);
    color: var(--color-text-primary);
}

.hidden {
    display: none !important;
}

/* Modal */
.modal-backdrop {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.7);
    z-index: 1000;
}

.modal {
    position: fixed;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    z-index: 1001;
    max-width: 560px;
    width: 90%;
