    padding: 20px 24px;
    border-bottom: 1px solid var(--color-border);
}

.modal-header h2 {
    font-size: 20px;
}

.btn-close {
    background: transparent;
    border: none;
    color: var(--color-text-muted);
    cursor: pointer;
    padding: 4px;
    transition: var(--transition);
}

.btn-close:hover {
    color: var(--color-text-primary);
}

.modal-body {
    padding: 24px;
}

.modal-footer {
    display: flex;
    justify-content: flex-end;
    gap: 12px;
    padding: 20px 24px;
    border-top: 1px solid var(--color-border);
}

.template-select {
    margin-top: 16px;
}

.template-options {
    display: grid;
    grid-template-columns: 1fr;
    gap: 8px;
    margin-top: 8px;
}

.template-option {
    display: flex;
    align-items: flex-start;
    gap: 12px;
    padding: 12px;
