}

.template-desc {
    font-size: 12px;
    color: var(--color-text-muted);
}

/* Utility */
.delete-actions {
    margin-top: 24px;
    padding-top: 16px;
    border-top: 1px solid var(--color-border);
}

.delete-actions .btn-danger {
    width: 100%;
