// workflow-editor - 可视化流程配置编辑器
// 前端JavaScript逻辑

// 全局状态
let appState = {
    currentWorkflow: null,
    currentNodeId: null,
    workflowData: {
        workflow: {},
        broadcast: {},
        roles: {},
        nodes: []
    },
    selectedNode: null,
    zoom: 1,
    isDragging: false,
    dragNode: null,
    dragOffset: { x: 0, y: 0 },
    isConnecting: false,
    connectionStart: null
};

// DOM Elements
const elements = {
    welcomeScreen: document.getElementById('welcome-screen'),
    editorScreen: document.getElementById('editor-screen'),
    workflowList: document.getElementById('workflow-list'),
    btnNewWorkflow: document.getElementById('btn-new-workflow'),
    btnNewValidate: document.getElementById('btn-validate'),
    btnSave: document.getElementById('btn-save'),
    canvas: document.getElementById('canvas'),
    yamlOutput: document.getElementById('yaml-output'),
    yamlPanel: document.querySelector('.yaml-panel'),
    btnToggleYaml: document.getElementById('btn-toggle-yaml'),
    btnCopyYaml: document.getElementById('btn-copy-yaml'),
    modalNew: document.getElementById('modal-new'),
    modalBackdrop: document.getElementById('modal-backdrop'),
    nodeProperties: document.getElementById('node-properties'),
    noSelection: document.getElementById('no-selection')
};

// 工具函数
function $(id) { return document.getElementById(id); }

// 初始化
document.addEventListener('DOMContentLoaded', () => {
    initializeEventListeners();
    loadWorkflowList();
    updateYamlPreview();
});

// 绑定事件监听
function initializeEventListeners() {
    // 新建流程按钮
    elements.btnNewWorkflow.addEventListener('click', openNewWorkflowModal);

    // 模态框按钮
    $('btn-close-modal-new').addEventListener('click', closeNewWorkflowModal);
    $('btn-cancel-new').addEventListener('click', closeNewWorkflowModal);
    $('btn-confirm-new').addEventListener('click', createNewWorkflow);
    elements.modalBackdrop.addEventListener('click', closeAllModals);

    // YAML面板
    elements.btnToggleYaml.addEventListener('click', toggleYamlPanel);
    elements.btnCopyYaml.addEventListener('click', copyYamlToClipboard);

    // 画布缩放
    $('btn-zoom-in').addEventListener('click', () => {
        appState.zoom *= 1.2;
        updateCanvasTransform();
    });
    $('btn-zoom-out').addEventListener('click', () => {
        appState.zoom /= 1.2;
        updateCanvasTransform();
    });
    $('btn-reset-zoom').addEventListener('click', () => {
        appState.zoom = 1;
        updateCanvasTransform();
    });

    // 拖拽节点类型到画布
    document.querySelectorAll('.node-type-item').forEach(item => {
        item.addEventListener('dragstart', handleDragStart);
    });

    elements.canvas.addEventListener('dragover', handleDragOver);
    elements.canvas.addEventListener('drop', handleDrop);

    // 画布鼠标事件（移动节点）
    elements.canvas.addEventListener('mousedown', handleCanvasMouseDown);
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);

    // 表单事件
    $('form-workflow-id').addEventListener('input', updateWorkflowDataFromForm);
    $('form-workflow-name').addEventListener('input', updateWorkflowDataFromForm);
    $('form-workflow-desc').addEventListener('input', updateWorkflowDataFromForm);
    $('form-workflow-version').addEventListener('input', updateWorkflowDataFromForm);

    // 属性面板事件
    $('prop-id').addEventListener('input', onPropertyChange);
    $('prop-name').addEventListener('input', onPropertyChange);
    $('prop-description').addEventListener('input', onPropertyChange);
    $('prop-role').addEventListener('change', onPropertyChange);
    $('prop-action').addEventListener('input', onPropertyChange);
    $('prop-timeout').addEventListener('change', onPropertyChange);
    $('prop-broadcast').addEventListener('change', onPropertyChange);
    $('prop-end').addEventListener('change', onPropertyChange);
    $('prop-next').addEventListener('change', onPropertyChange);

    // 按钮事件
    $('btn-add-decision').addEventListener('click', addDecisionField);
    $('btn-add-check').addEventListener('click', addCheckField);
    $('btn-delete-node').addEventListener('click', deleteSelectedNode);
    $('btn-add-role').addEventListener('click', addRoleField);
    $('btn-validate').addEventListener('click', validateWorkflow);
    $('btn-save').addEventListener('click', saveWorkflow);
}

// 加载流程列表
async function loadWorkflowList() {
    try {
        // 这里通过OpenClaw API获取列表
        // 前端演示模式：内置模板 + 读取localStorage自定义
        const builtinTemplates = [
            { id: 'requirement-review', name: '需求评审流程', description: '标准需求评审协作流程' },
            { id: 'release-checklist', name: '上线发布检查流程', description: '上线前多角色确认检查' },
            { id: 'post-mortem', name: '故障复盘流程', description: '故障根因分析和改进' }
        ];

        const customWorkflows = JSON.parse(localStorage.getItem('customWorkflows') || '[]');
        const allWorkflows = [...builtinTemplates, ...customWorkflows];

        renderWorkflowList(allWorkflows);
    } catch (err) {
        console.error('Failed to load workflow list:', err);
        elements.workflowList.innerHTML = '<div class="loading">加载失败</div>';
    }
}

// 渲染流程列表
function renderWorkflowList(workflows) {
    if (workflows.length === 0) {
        elements.workflowList.innerHTML = '<div class="loading">暂无流程</div>';
        return;
    }

    elements.workflowList.innerHTML = workflows.map(w => `
        <div class="workflow-item ${appState.currentWorkflow === w.id ? 'active' : ''}" data-id="${w.id}" onclick="loadWorkflow('${w.id}')">
            <div class="workflow-item-name">${w.name}</div>
            <div class="workflow-item-desc">${w.description || ''}</div>
        </div>
    `).join('');
}

// 打开新建流程模态框
function openNewWorkflowModal() {
    elements.modalNew.classList.remove('hidden');
    elements.modalBackdrop.classList.remove('hidden');
}

// 关闭新建模态框
function closeNewWorkflowModal() {
    elements.modalNew.classList.add('hidden');
    elements.modalBackdrop.classList.add('hidden');
}

// 关闭所有模态框
function closeAllModals() {
    document.querySelectorAll('.modal').forEach(m => m.classList.add('hidden'));
    elements.modalBackdrop.classList.add('hidden');
}

// 创建新流程
function createNewWorkflow() {
    const id = $('modal-id').value.trim();
    const name = $('modal-name').value.trim();
    const desc = $('modal-desc').value.trim();
    const template = document.querySelector('input[name="template"]:checked').value;

    // 验证ID
    if (!/^[a-z0-9-]+$/.test(id)) {
        alert('流程ID只能包含小写字母、数字和连字符');
        return;
    }

    if (!name) {
        alert('请输入流程名称');
        return;
    }

    let initialData;

    if (template === 'blank') {
        initialData = {
            workflow: { id, name, description: desc, version: '1.0', created_at: new Date().toISOString().split('T')[0] },
            broadcast: { enabled: true, channel: 'both', feishu_chat_id: '', show_full_messages: true, show_progress: true },
            roles: {
                product: { name: '产品经理', description: '发起流程', session_key: 'productmanager' }
            },
            nodes: [
                { id: 'start', name: '开始', role: 'product', description: '流程起点', action: '开始流程', next: 'end', end: false },
                { id: 'end', name: '结束', description: '流程终点', end: true }
            ]
        };

        // 给节点默认位置
        initialData.nodes[0].x = 200;
        initialData.nodes[0].y = 200;
        initialData.nodes[1].x = 400;
        initialData.nodes[1].y = 200;
    } else {
        // 从模板加载
        initialData = getTemplateData(template);
        initialData.workflow.id = id;
        initialData.workflow.name = name;
        if (desc) {
            initialData.workflow.description = desc;
        }
        // 重新计算位置
        initialData.nodes.forEach((node, i) => {
            node.x = 200 + i * 200;
            node.y = 200;
        });
    }

    appState.workflowData = initialData;
    appState.currentWorkflow = id;
    appState.selectedNode = null;

    // 保存到localStorage（实际环境会保存到服务器/文件）
    saveCustomWorkflowToList(id, name, desc);

    // 切换到编辑界面
    elements.welcomeScreen.classList.add('hidden');
    elements.editorScreen.classList.remove('hidden');

    // 更新表单
    updateFormFromData();
    // 重新渲染画布
    renderCanvas();
    // 更新YAML预览
    updateYamlPreview();
    // 更新面包屑
    $('breadcrumb-workflow').textContent = name;

    closeNewWorkflowModal();
    loadWorkflowList();
}

// 获取模板数据
function getTemplateData(templateId) {
    const templates = {
        'requirement-review': {
            workflow: {
                id: 'requirement-review',
                name: '需求评审流程',
                description: '标准需求评审协作流程',
                version: '1.0',
                created_at: new Date().toISOString().split('T')[0]
            },
            broadcast: { enabled: true, channel: 'both', feishu_chat_id: '', show_full_messages: true, show_progress: true },
            roles: {
                product: { name: '产品经理', description: '发起需求，汇总评审结果', session_key: 'productmanager' },
                design: { name: '设计师', description: '给出设计反馈', session_key: 'designer' },
                development: { name: '开发工程师', description: '给出技术评估', session_key: 'development' },
                test: { name: '测试工程师', description: '给出测试风险评估', session_key: 'tester' }
