// 保存自定义流程到列表
function saveCustomWorkflowToList(id, name, description) {
    const custom = JSON.parse(localStorage.getItem('customWorkflows') || '[]');
    const existingIndex = custom.findIndex(w => w.id === id);
    const newItem = { id, name, description };
    if (existingIndex >= 0) {
        custom[existingIndex] = newItem;
    } else {
        custom.push(newItem);
    }
    localStorage.setItem('customWorkflows', JSON.stringify(custom));
}

// 加载已有流程
function loadWorkflow(workflowId) {
    // 先尝试从localStorage加载自定义，再用内置模板
    let workflowData = null;

    try {
        const customStr = localStorage.getItem(`workflow_${workflowId}`);
        if (customStr) {
            workflowData = JSON.parse(customStr);
        }
    } catch (err) {
        console.error('Failed to load custom workflow:', err);
    }

    if (!workflowData) {
        // 从内置模板
        workflowData = getTemplateData(workflowId);
    }

    // 确保每个节点有x,y坐标
    workflowData.nodes.forEach((node, i) => {
        if (typeof node.x !== 'number') {
            node.x = 200 + i * 180;
            node.y = 200 + Math.floor(i / 3) * 150;
        }
    });

    appState.workflowData = workflowData;
    appState.currentWorkflow = workflowId;
    appState.selectedNode = null;

    // 切换到编辑界面
    elements.welcomeScreen.classList.add('hidden');
    elements.editorScreen.classList.remove('hidden');

    // 更新界面
    updateFormFromData();
    renderCanvas();
    updateYamlPreview();
    $('breadcrumb-workflow').textContent = workflowData.workflow.name;
    loadWorkflowList();
}

