// 渲染画布
function renderCanvas() {
    // 清空画布
    elements.canvas.innerHTML = '<div class="canvas-empty hidden">拖拽左侧节点到这里开始构建流程</div>';
    if (appState.workflowData.nodes.length === 0) {
        elements.canvas.querySelector('.canvas-empty').classList.remove('hidden');
        return;
    }

    // 添加SVG用于连接线
    const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.style.position = 'absolute';
    svg.style.top = '0';
    svg.style.left = '0';
    svg.style.width = '100%';
    svg.style.height = '100%';
    svg.style.pointerEvents = 'none';
    elements.canvas.appendChild(svg);

    // 渲染每个节点
    appState.workflowData.nodes.forEach(node => {
        const nodeEl = createNodeElement(node);
        nodeEl.style.left = node.x + 'px';
        nodeEl.style.top = node.y + 'px';
        elements.canvas.appendChild(nodeEl);
    });

    // 绘制连接线
    renderConnections(svg);
}

// 创建节点DOM元素
function createNodeElement(node) {
    const el = document.createElement('div');
    el.className = `canvas-node ${get_node_type_class(node)} ${node.id === appState.selectedNode ? 'selected' : ''}`;
    el.dataset.id = node.id;

    const iconMap = {
        start: 'fa-play-circle',
        end: 'fa-stop-circle',
        decision: 'fa-sitemap',
        task: 'fa-tasks'
    };

    const iconClass = iconMap[get_node_type_class(node)] || iconMap.task;
    const nodeTypeLabel = {
        start: '开始',
        end: '结束',
        decision: '决策',
        task: '任务'
    };

    el.innerHTML = `
        <div class="canvas-node-header">
            <div class="canvas-node-icon">
                <i class="fas ${iconClass}"></i>
            </div>
            <div class="canvas-node-title">${escapeHtml(node.name || node.id)}</div>
            ${node.role ? `<div class="canvas-node-role">${escapeHtml(getRoleName(node.role))}</div>` : ''}
        </div>
        ${node.description ? `<div class="canvas-node-desc">${escapeHtml(node.description)}</div>` : ''}
    `;

    el.addEventListener('mousedown', (e) => {
        if (e.target.closest('.btn-delete-item')) return;
        selectNode(node.id);
        startDrag(e, node.id);
    });

    return el;
}

function get_node_type_class(node) {
    if (node.end) return 'end';
    if (node.decisions && node.decisions.length > 0) return 'decision';
    if (node.id === 'start' || node.next === 'end') return 'start';
    return 'task';
}

function getRoleName(roleKey) {
    const role = appState.workflowData.roles[roleKey];
    return role ? role.name : roleKey;
}

// 绘制连接线
function renderConnections(svg) {
    appState.workflowData.nodes.forEach(node => {
        // 找出所有下一节点
        let nextIds = [];
        if (node.next) {
            nextIds = [node.next];
        }
        if (node.decisions) {
            node.decisions.forEach(d => {
                if (d.next && !nextIds.includes(d.next)) {
                    nextIds.push(d.next);
                }
            });
        }
        // 到end节点也要连线
        if (node.end && node.id !== 'end') {
            const endNode = appState.workflowData.nodes.find(n => n.end);
            if (endNode && !nextIds.includes(endNode.id)) {
                nextIds.push(endNode.id);
            }
        }

        nextIds.forEach(nextId => {
            const nextNode = appState.workflowData.nodes.find(n => n.id === nextId);
            if (nextNode) {
                drawConnection(svg, node, nextNode);
            }
        });
    });
}

// 绘制一条连接线
function drawConnection(svg, fromNode, toNode) {
    // 计算坐标：节点中心
    const fromX = fromNode.x + 100; // 节点一半宽度
    const fromY = fromNode.y + 40; // 大概中心Y
    const toX = toNode.x + 100;
    const toY = toNode.y + 40;

    // 贝塞尔曲线
    const midX = (fromX + toX) / 2;
    const path = `M ${fromX} ${fromY} C ${midX} ${fromY}, ${midX} ${toY}, ${toX} ${toY}`;

    const pathEl = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    pathEl.setAttribute('d', path);
    pathEl.setAttribute('class', 'canvas-connection');

    // 箭头
    const arrowMarker = document.createElementNS('http://www.w3.org/2000/svg', 'defs');
    const marker = document.createElementNS('http://www.w3.org/2000/svg', 'marker');
    marker.setAttribute('id', `arrow-${fromNode.id}-${toNode.id}`);
    marker.setAttribute('markerWidth', '10');
    marker.setAttribute('markerHeight', '10');
    marker.setAttribute('refX', '8');
    marker.setAttribute('refY', '3');
    marker.setAttribute('orient', 'auto');
    const polygon = document.createElementNS('http://www.w3.org/2000/svg', 'polygon');
    polygon.setAttribute('points', '0 0, 10 3, 0 6');
    polygon.setAttribute('class', 'canvas-connection-arrow');
    marker.appendChild(polygon);
    arrowMarker.appendChild(marker);
    pathEl.setAttribute('marker-end', `url(#arrow-${fromNode.id}-${toNode.id})`);

    svg.appendChild(arrowMarker);
    svg.appendChild(pathEl);
}

// 拖拽开始（从节点面板）
function handleDragStart(e) {
    e.dataTransfer.setData('node-type', e.currentTarget.dataset.type);
}

function handleDragOver(e) {
    e.preventDefault();
}

function handleDrop(e) {
    e.preventDefault();
    const nodeType = e.dataTransfer.getData('node-type');
    const rect = elements.canvas.getBoundingClientRect();
    const x = e.clientX - rect.left - 100;
    const y = e.clientY - rect.top - 40;

    createNewNode(nodeType, x, y);
    updateYamlPreview();
}

// 创建新节点
function createNewNode(type, x, y) {
    const id = `node_${Date.now()}`;
    const names = {
        start: '开始节点',
        task: '新任务',
        decision: '决策节点',
        end: '结束节点'
    };

    const newNode = {
        id,
        name: names[type] || '新节点',
        description: '',
        action: '',
        role: '',
        timeout_hours: 24,
        broadcast: true,
        x, y
    };

    if (type === 'start') {
        newNode.end = false;
    } else if (type === 'end') {
        newNode.end = true;
    } else {
        newNode.end = false;
        newNode.next = '';
    }

    if (type === 'decision') {
        newNode.decisions = [];
    }

    appState.workflowData.nodes.push(newNode);
    renderCanvas();
    selectNode(id);
    return newNode;
}

// 选择节点
function selectNode(nodeId) {
    appState.selectedNode = nodeId;
    renderCanvas();
    updateNodePropertiesPanel();
}

// 更新节点属性面板
function updateNodePropertiesPanel() {
    if (!appState.selectedNode) {
        elements.nodeProperties.classList.add('hidden');
        elements.noSelection.classList.remove('hidden');
        return;
    }

    elements.nodeProperties.classList.remove('hidden');
    elements.noSelection.classList.add('hidden');

    const node = getCurrentNode();
    if (!node) return;

    $('prop-id').value = node.id || '';
    $('prop-name').value = node.name || '';
    $('prop-description').value = node.description || '';
    $('prop-action').value = node.action || '';
    $('prop-timeout').value = node.timeout_hours || 24;
    $('prop-broadcast').checked = node.broadcast !== false;
    $('prop-end').checked = !!node.end;

    // 更新角色下拉
    updateRoleSelect();
    // 更新下一节点下拉
    updateNextSelect();
    // 更新决策列表
    updateDecisionsList();
    // 更新检查项列表
    updateChecksList();

    // 显示/隐藏决策区域
    if (node.decisions) {
        $('decisions-section').classList.remove('hidden');
        $('.next-node-section').classList.add('hidden');
    } else {
        $('decisions-section').classList.add('hidden');
        $('.next-node-section').classList.remove('hidden');
    }

    if (node.end) {
        $('.next-node-section').classList.add('hidden');
        $('decisions-section').classList.add('hidden');
    }

    $('prop-role').value = node.role || '';
    $('prop-next').value = node.next || '';
}

