    if (!nodeId) return;
    if (!confirm(`确认删除节点 "${nodeId}"？`)) return;

    const index = appState.workflowData.nodes.findIndex(n => n.id === nodeId);
    if (index >= 0) {
        appState.workflowData.nodes.splice(index, 1);
    }
    // 清除其他节点对该节点的引用
    appState.workflowData.nodes.forEach(node => {
        if (node.next === nodeId) {
            node.next = '';
        }
        if (node.decisions) {
            node.decisions.forEach(d => {
                if (d.next === nodeId) {
                    d.next = '';
                }
            });
        }
    });

    appState.selectedNode = null;
    renderCanvas();
    updateNodePropertiesPanel();
    updateYamlPreview();
}

// 拖拽移动节点
function startDrag(e, nodeId) {
    appState.isDragging = true;
    appState.dragNode = nodeId;
    const node = appState.workflowData.nodes.find(n => n.id === nodeId);
    const rect = elements.canvas.getBoundingClientRect();
    appState.dragOffset = {
        x: e.clientX - rect.left - node.x,
        y: e.clientY - rect.top - node.y
    };
}

function handleCanvasMouseDown(e) {
    // 点击画布空白处取消选择
    if (e.target === elements.canvas || e.target.classList.contains('canvas-empty')) {
        appState.selectedNode = null;
        updateNodePropertiesPanel();
        renderCanvas();
    }
}

function handleMouseMove(e) {
    if (!appState.isDragging || !appState.dragNode) return;

    const node = appState.workflowData.nodes.find(n => n.id === appState.dragNode);
    if (!node) return;

    const rect = elements.canvas.getBoundingClientRect();
    node.x = e.clientX - rect.left - appState.dragOffset.x;
    node.y = e.clientY - rect.top - appState.dragOffset.y;

    // 重新渲染连接线
    renderCanvas();
}

function handleMouseUp() {
    if (appState.isDragging) {
        appState.isDragging = false;
        appState.dragNode = null;
        updateYamlPreview();
    }
}

// 更新YAML预览
function updateYamlPreview() {
    const yaml = generateYaml();
    elements.yamlOutput.textContent = yaml;
}

// 生成YAML
function generateYaml() {
    const data = appState.workflowData;
    let lines = [];

    // workflow
    lines.push(`# ${data.workflow.name}`);
    lines.push(``);
    lines.push(`workflow:`);
    lines.push(`  id: "${escapeYaml(data.workflow.id || '')}"`);
    lines.push(`  name: "${escapeYaml(data.workflow.name || '')}"`);
    if (data.workflow.description) {
        lines.push(`  description: "${escapeYaml(data.workflow.description)}"`);
    }
    lines.push(`  version: "${escapeYaml(data.workflow.version || '1.0')}"`);
    lines.push(`  created_at: "${data.workflow.created_at || new Date().toISOString().split('T')[0]}"`);
    lines.push(``);

    // broadcast
    lines.push(`# 全局广播配置`);
    lines.push(`broadcast:`);
    lines.push(`  enabled: ${data.broadcast.enabled ? 'true' : 'false'}`);
    lines.push(`  channel: "${escapeYaml(data.broadcast.channel || 'both')}"`);
    lines.push(`  feishu_chat_id: "${escapeYaml(data.broadcast.feishu_chat_id || '')}"`);
    lines.push(`  show_full_messages: true`);
    lines.push(`  show_progress: true`);
    lines.push(``);

    // roles
    lines.push(`# 参与角色定义`);
    lines.push(`roles:`);
    Object.keys(data.roles).forEach(key => {
        const role = data.roles[key];
        lines.push(`  ${key}:`);
        lines.push(`    name: "${escapeYaml(role.name || '')}"`);
        if (role.description) {
            lines.push(`    description: "${escapeYaml(role.description)}"`);
        }
        if (role.session_key) {
            lines.push(`    session_key: "${escapeYaml(role.session_key)}"`);
        }
        if (role.label) {
            lines.push(`    label: "${escapeYaml(role.label)}"`);
        }
        if (role.agentId) {
            lines.push(`    agentId: "${escapeYaml(role.agentId)}"`);
        }
    });
    lines.push(``);

    // nodes
    lines.push(`# 流程节点定义`);
    lines.push(`nodes:`);
    data.nodes.forEach(node => {
        lines.push(`  - id: "${escapeYaml(node.id || '')}"`);
        lines.push(`    name: "${escapeYaml(node.name || '')}"`);
        if (node.role) {
            lines.push(`    role: ${node.role}`);
        }
        if (node.description) {
            lines.push(`    description: "${escapeYaml(node.description)}"`);
        }
        if (node.action) {
            lines.push(`    action: |`);
            // 缩进action内容
            node.action.split('\n').forEach(line => {
                lines.push(`      ${line}`);
            });
        }
        if (node.checks && node.checks.length > 0) {
            lines.push(`    checks:`);
            node.checks.forEach(check => {
                lines.push(`      - "${escapeYaml(check)}"`);
            });
        }
        if (node.timeout_hours) {
            lines.push(`    timeout_hours: ${node.timeout_hours}`);
        }
        if (typeof node.broadcast !== 'undefined') {
            lines.push(`    broadcast: ${node.broadcast}`);
        }
        if (node.next && !node.decisions) {
            lines.push(`    next: ${node.next}`);
        }
        if (node.decisions && node.decisions.length > 0) {
            lines.push(`    decisions:`);
            node.decisions.forEach(d => {
                lines.push(`      - key: "${escapeYaml(d.key || '')}"`);
                lines.push(`        label: "${escapeYaml(d.label || '')}"`);
                lines.push(`        next: ${d.next || ''}`);
            });
        }
        if (node.end) {
            lines.push(`    end: true`);
        } else if (typeof node.end !== 'undefined') {
            lines.push(`    end: false`);
        }
        lines.push(``);
    });

    return lines.join('\n');
}

function escapeYaml(str) {
    if (typeof str !== 'string') return str;
    return str.replace(/"/g, '\\"');
}

function escapeHtml(str) {
    if (typeof str !== 'string') return str;
    return str
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#039;');
}

// 切换YAML面板
function toggleYamlPanel() {
    elements.yamlPanel.classList.toggle('collapsed');
    const icon = elements.btnToggleYaml.querySelector('i');
    if (elements.yamlPanel.classList.contains('collapsed')) {
        icon.className = 'fas fa-chevron-up';
    } else {
        icon.className = 'fas fa-chevron-down';
    }
}

// 复制YAML
async function copyYamlToClipboard() {
    try {
        await navigator.clipboard.writeText(elements.yamlOutput.textContent);
        const btn = elements.btnCopyYaml;
        const oldIcon = btn.innerHTML;
        btn.innerHTML = '<i class="fas fa-check"></i>';
        setTimeout(() => {
            btn.innerHTML = oldIcon;
        }, 2000);
    } catch (err) {
        console.error('Failed to copy:', err);
        alert('复制失败，请手动复制');
    }
}

// 验证工作流
function validateWorkflow() {
    const errors = [];

    // 检查基本信息
    if (!appState.workflowData.workflow.id) {
        errors.push('缺少流程ID');
    }
    if (!appState.workflowData.workflow.name) {
        errors.push('缺少流程名称');
    }
    if (!/^[a-z0-9-]+$/.test(appState.workflowData.workflow.id)) {
        errors.push('流程ID只能包含小写字母、数字、连字符');
    }

    // 检查节点ID唯一
    const nodeIds = new Set();
    appState.workflowData.nodes.forEach(node => {
        if (!node.id) {
            errors.push('存在节点缺少ID');
        } else if (nodeIds.has(node.id)) {
            errors.push(`节点ID重复: ${node.id}`);
        }
        nodeIds.add(node.id);
    });

    // 检查next引用存在
    appState.workflowData.nodes.forEach(node => {
        if (node.next && !nodeIds.has(node.next)) {
            errors.push(`节点 "${node.id}" 引用不存在的下一节点: ${node.next}`);
        }
        if (node.decisions) {
            node.decisions.forEach(d => {
                if (d.next && !nodeIds.has(d.next)) {
                    errors.push(`节点 "${node.id}" 决策 "${d.key}" 引用不存在的下一节点: ${d.next}`);
                }
            });
        }
        if (node.role && !appState.workflowData.roles[node.role]) {
            errors.push(`节点 "${node.id}" 引用不存在的角色: ${node.role}`);
        }
    });

    // 检查至少有一个结束节点
    const hasEnd = appState.workflowData.nodes.some(n => n.end);
    if (!hasEnd) {
        errors.push('至少需要一个结束节点');
    }

    if (errors.length > 0) {
        alert('验证发现问题:\n' + errors.map(e => `- ${e}`).join('\n'));
        return false;
    } else {
        alert('✅ 验证通过！配置正确');
        return true;
    }
}

// 保存工作流
function saveWorkflow() {
    if (!validateWorkflow()) {
        return;
    }

    // 保存到 localStorage（实际环境会保存到文件系统）
    try {
        localStorage.setItem(`workflow_${appState.currentWorkflow}`, JSON.stringify(appState.workflowData));
        saveCustomWorkflowToList(
            appState.workflowData.workflow.id,
            appState.workflowData.workflow.name,
            appState.workflowData.workflow.description
        );
        // 生成YAML供下载
        downloadYaml();
        loadWorkflowList();
        alert('✅ 保存成功！YAML已下载');
    } catch (err) {
        console.error('Save failed:', err);
        alert('保存失败: ' + err.message);
    }
}

// 下载YAML文件
function downloadYaml() {
    const yaml = generateYaml();
    const blob = new Blob([yaml], { type: 'text/yaml' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${appState.currentWorkflow}.yaml`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}

// 更新画布变换（缩放）
function updateCanvasTransform() {
    elements.canvas.style.transform = `scale(${appState.zoom})`;
    elements.canvas.style.transformOrigin = 'top left';
}

// 全局导出需要被html调用的函数
window.loadWorkflow = loadWorkflow;
window.updateDecision = updateDecision;
window.deleteDecision = deleteDecision;
window.updateCheck = updateCheck;
window.deleteCheck = deleteCheck;
window.addDecisionField = addDecisionField;
window.addCheckField = addCheckField;
window.updateRole = updateRole;
window.deleteRole = deleteRole;
window.addRoleField = addRoleField;
EOF

