/* Code编辑器占位 */
.code-editor-placeholder textarea {
  min-height: 180px;
  font-family: 'Menlo', 'Monaco', 'Courier New', monospace;
  font-size: 13px;
  line-height: 1.5;
}

/* Toast */
.toast-container {
  position: fixed;
  top: 80px;
  left: 50%;
  transform: translateX(-50%);
  z-index: 9999;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
  pointer-events: none;
}

.toast {
  padding: 12px 20px;
  background: var(--color-bg-white);
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-md);
  min-width: 200px;
  max-width: 80vw;
  animation: toast-in 0.3s ease;
}

.toast.success {
  border-left: 4px solid var(--color-success);
}

.toast.error {
  border-left: 4px solid var(--color-danger);
}

@keyframes toast-in {
  from {
    transform: translateY(-20px);
    opacity: 0;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}

/* 空状态 */
.empty-state {
  text-align: center;
  padding: 60px 20px;
  color: var(--color-text-secondary);
}

.empty-state i {
  font-size: 48px;
  color: var(--color-text-placeholder);
  margin-bottom: 16px;
}

.empty-state p {
  font-size: 16px;
  margin-bottom: 24px;
}

/* 分页 */
.pagination {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-2);
  margin-top: var(--spacing-8);
}

.pagination-item {
  min-width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  background: var(--color-bg-white);
  cursor: pointer;
  transition: all 0.2s;
}

.pagination-item:hover:not(.active):not(.disabled) {
  border-color: var(--color-primary);
  color: var(--color-primary);
}

.pagination-item.active {
  background: var(--color-primary);
  color: white;
  border-color: var(--color-primary);
}

.pagination-item.disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.pagination-more {
  color: var(--color-text-secondary);
  padding: 0 8px;
}

/* 链接文字 */
.link-text {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: var(--color-primary);
  font-size: 14px;
  text-decoration: none;
}

.link-text:hover {
  text-decoration: underline;
}

/* 下拉菜单 */
.dropdown {
  position: relative;
}

.dropdown-menu.hidden {
  display: none;
}

/* 进度条 */
.progress-bar {
  width: 100%;
  height: 8px;
  background: var(--color-bg-light);
  border-radius: 4px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  background: var(--color-primary);
  border-radius: 4px;
  transition: width 0.3s ease;
}

/* 响应式 */
@media (max-width: 768px) {
  .nav-menu {
    gap: var(--spacing-3);
  }
  .container {
    padding: 0 var(--spacing-4);
  }
  .main-content {
    padding: var(--spacing-4) 0;
  }
}
