// 全站通用JavaScript - 方法论专家

// Toast通知
function showToast(message, type = 'info') {
  const container = document.getElementById('toast-container');
  const toast = document.createElement('div');
  toast.className = `toast ${type}`;
  toast.innerHTML = message;
  container.appendChild(toast);

  setTimeout(() => {
    toast.style.opacity = '0';
    setTimeout(() => {
      container.removeChild(toast);
    }, 300);
  }, 3000);
}

// 下拉菜单处理
document.addEventListener('click', function(e) {
  // 点击下拉按钮
  if (e.target.closest('.user-dropdown .user-button')) {
    const dropdown = e.target.closest('.user-dropdown').querySelector('.dropdown-menu');
    dropdown.classList.toggle('hidden');
    return;
  }

  // 点击其他地方关闭下拉
  if (!e.target.closest('.dropdown-menu')) {
    document.querySelectorAll('.dropdown-menu').forEach(menu => {
      if (!menu.contains(e.target)) {
        menu.classList.add('hidden');
      }
    });
  }
});

// 文件上传处理
function handleFileUpload(file, onProgress, onComplete, onError) {
  // 检查大小
  const maxSize = 10 * 1024 * 1024; // 10MB
  if (file.size > maxSize) {
    showToast('文件大小超过10MB，请压缩后重新上传', 'error');
    onError('file too large');
    return;
  }

  // 检查格式
  const allowedTypes = ['.txt', '.md', '.pdf'];
  const ext = '.' + file.name.split('.').pop().toLowerCase();
  if (!allowedTypes.includes(ext)) {
    showToast('不支持该文件格式，请上传txt/md/pdf', 'error');
    onError('format not supported');
    return;
  }

  // 模拟上传进度（实际项目中用XHR或fetch）
  let progress = 0;
  const interval = setInterval(() => {
    progress += Math.random() * 30;
    if (progress > 100) progress = 100;
    onProgress(progress);
    if (progress === 100) {
      clearInterval(interval);
      setTimeout(() => {
        onComplete(file);
      }, 300);
    }
  }, 100);
}

// 防抖
function debounce(fn, delay) {
  let timeout;
  return function(...args) {
    clearTimeout(timeout);
    timeout = setTimeout(() => fn.apply(this, args), delay);
  };
}

// 工具函数
function escapeHtml(text) {
  const map = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;'
  };
  return text.replace(/[&<>"']/g, m => map[m]);
}
